const RESERVED_SLUGS = ['admin', 'super-admin', 'login', 'api', 'assets', 'system', 'home', 'perfil', 'busca', 'hub', 'biblioteca'];

export const AdminSettings = () => {
  const { linkName } = useParams();
  const navigate = useNavigate();
  const { companies, updateCompany } = useAppStore();

  const company = companies.find(c => c.linkName === linkName);

  const [formData, setFormData] = useState({
    name: '',
    linkName: '',
    logoUrl: '',
    heroImage: '',
    heroTitle: '',
    heroSubtitle: '',
    active: true
  });

  // Inicializa o form com os dados da empresa
  useEffect(() => {
    if (company) {
      setFormData({
        name: company.name,
        linkName: company.linkName,
        logoUrl: company.logoUrl || '',
        heroImage: company.heroImage || '',
        heroTitle: company.heroTitle || '',
        heroSubtitle: company.heroSubtitle || '',
        active: company.active
      });
    }
  }, [company]);

  if (!company) return null;

  const handleLinkNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newLink = e.target.value.toLowerCase().replace(/[\s\W-]+/g, '');
    setFormData(prev => ({ ...prev, linkName: newLink }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'logoUrl' | 'heroImage') => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Limite de 10MB para o arquivo bruto
    if (file.size > 10 * 1024 * 1024) {
      toast.error('A imagem é muito grande (máximo 10MB).');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        // Limita a resolução para proteger a memória (Hero = 1280px, Logo = 400px)
        const maxWidth = field === 'heroImage' ? 1280 : 400;

        if (width > maxWidth) {
          height = Math.round((height * maxWidth) / width);
          width = maxWidth;
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        if (ctx) {
          // Fundo branco para caso a imagem tenha transparência (útil para JPEG)
          ctx.fillStyle = '#FFFFFF';
          ctx.fillRect(0, 0, width, height);
          ctx.drawImage(img, 0, 0, width, height);

          // Comprime como JPEG com 80% de qualidade
          const compressedUrl = canvas.toDataURL('image/jpeg', 0.8);
          setFormData(prev => ({ ...prev, [field]: compressedUrl }));
        } else {
          // Fallback caso o canvas falhe
          setFormData(prev => ({ ...prev, [field]: event.target?.result as string }));
        }
      };
      img.src = event.target?.result as string;
    };
    reader.readAsDataURL(file);

    // Reseta o input para permitir upload da mesma imagem se necessário
    e.target.value = '';
  };

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();

    const name = formData.name.trim();
    const newLinkName = formData.linkName.trim();

    if (!name || !newLinkName) {
      return toast.error('Nome e Link de Acesso são obrigatórios.');
    }

    if (RESERVED_SLUGS.includes(newLinkName)) {
      return toast.error(`O link "${newLinkName}" é reservado pelo sistema e não pode ser utilizado.`);
    }

    const isDuplicate = companies.some(c => c.linkName === newLinkName && c.id !== company.id);
    if (isDuplicate) {
      return toast.error('Este Link de Acesso já está em uso por outra empresa.');
    }

    try {
      updateCompany(company.id, formData);
      toast.success('Configurações atualizadas com sucesso!');

      if (newLinkName !== company.linkName) {
        navigate(`/admin/${newLinkName}/settings`, { replace: true });
      }
    } catch (err: any) {
      if (err?.name === 'QuotaExceededError' || err?.message?.includes('exceeded the quota')) {
         toast.error('Limite de armazenamento do navegador atingido! Use uma imagem menor ou através de um link de URL.');
      } else {
         toast.error('Erro inesperado ao salvar as configurações.');
      }
      console.error("Erro ao salvar configurações da empresa:", err);
    }
  };

  return (
    <div className="max-w-4xl mx-auto pb-12">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-slate-900">Configurações da Empresa</h1>
        <p className="text-sm text-slate-500 mt-1">
          Gerencie os dados básicos e a página inicial da <strong>{company.name}</strong>.
        </p>
      </div>

      <form onSubmit={handleSaveSettings} className="space-y-6">
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-6 md:p-8 space-y-8">

            {/* Seção Básica */}
            <div>
              <h2 className="text-lg font-semibold text-slate-900 mb-4 border-b border-slate-100 pb-2">Informações Principais</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label>Nome da Empresa *</Label>
                  <Input 
                    placeholder="Ex: Globex Corp" 
                    value={formData.name} 
                    onChange={(e) => setFormData(prev => ({...prev, name: e.target.value}))} 
                  />
                </div>

                <div className="space-y-2">
                  <Label>Link de Acesso (URL) *</Label>
                  <div className="flex shadow-sm rounded-md overflow-hidden border border-slate-200 transition-colors focus-within:border-indigo-500 focus-within:ring-1 focus-within:ring-indigo-500">
                    <span className="flex items-center px-3 bg-slate-50 text-slate-500 text-sm font-mono border-r border-slate-200">
                      seusite.com/
                    </span>
                    <Input 
                      className="border-0 rounded-none focus-visible:ring-0 px-3 shadow-none bg-white font-mono" 
                      placeholder="minhaempresa" 
                      value={formData.linkName} 
                      onChange={handleLinkNameChange} 
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Logo */}
            <div>
              <h2 className="text-lg font-semibold text-slate-900 mb-4 border-b border-slate-100 pb-2">Logomarca</h2>
              <div className="flex flex-col sm:flex-row gap-6 items-start">
                 <div className="w-24 h-24 rounded-xl border-2 border-slate-200 bg-slate-50 flex items-center justify-center overflow-hidden shrink-0 shadow-inner">
                    {formData.logoUrl ? (
                      <img src={formData.logoUrl} alt="Logo" className="w-full h-full object-cover" />
                    ) : (
                      <Building className="text-slate-300" size={32} />
                    )}
                 </div>
                 <div className="flex-1 space-y-3 w-full">
                    <Input type="file" accept="image/*" onChange={(e) => handleImageUpload(e, 'logoUrl')} className="hidden" id="company-logo-upload" />
                    <Button type="button" variant="outline" onClick={() => document.getElementById('company-logo-upload')?.click()} className="flex items-center gap-2">
                      <Upload size={16} /> Fazer Upload da Logo
                    </Button>
                    <div className="flex flex-col gap-1.5">
                       <Label className="text-xs text-slate-500">Ou cole a URL da imagem (https://...)</Label>
                       <Input placeholder="https://exemplo.com/logo.png" value={formData.logoUrl} onChange={(e) => setFormData(prev => ({...prev, logoUrl: e.target.value}))} className="text-sm max-w-md" />
                    </div>
                 </div>
              </div>
            </div>

            {/* Capa do Painel do Usuário (Hero Banner) */}
            <div>
              <h2 className="text-lg font-semibold text-slate-900 mb-4 border-b border-slate-100 pb-2">Capa do Painel (Home do Usuário)</h2>
              <p className="text-sm text-slate-500 mb-4">Defina o grande banner que aparece no topo quando o colaborador acessa a plataforma.</p>

              <div className="space-y-4">
                 <div className="space-y-2">
                    <Label>Imagem de Capa (Banner)</Label>
                    <div className="border-2 border-dashed border-slate-200 rounded-lg p-2 flex flex-col items-center justify-center relative bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer group h-40 overflow-hidden" onClick={() => document.getElementById('hero-upload')?.click()}>
                       {formData.heroImage ? (
                          <>
                            <img src={formData.heroImage} alt="Capa" className="w-full h-full object-cover rounded-md opacity-80 group-hover:opacity-40 transition-opacity" />
                            <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"><Button type="button" variant="secondary" size="sm">Trocar Imagem</Button></div>
                          </>
                       ) : (
                          <div className="text-center p-4">
                             <ImageIcon className="mx-auto h-8 w-8 text-slate-400 mb-2" />
                             <p className="text-xs text-slate-500">Proporção ideal: 16:9</p>
                          </div>
                       )}
                    </div>
                    <Input type="file" accept="image/*" onChange={(e) => handleImageUpload(e, 'heroImage')} className="hidden" id="hero-upload" />
                    <Input placeholder="Ou cole a URL da imagem..." value={formData.heroImage} onChange={(e) => setFormData(prev => ({...prev, heroImage: e.target.value}))} className="h-8 text-xs mt-2" />
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <div className="space-y-2">
                     <Label>Título Principal</Label>
                     <Input placeholder="Ex: Treinamento de Vendas 2024" value={formData.heroTitle} onChange={(e) => setFormData(prev => ({...prev, heroTitle: e.target.value}))} />
                   </div>
                   <div className="space-y-2">
                     <Label>Subtítulo / Descrição</Label>
                     <Input placeholder="Ex: Assista aos novos conteúdos disponibilizados." value={formData.heroSubtitle} onChange={(e) => setFormData(prev => ({...prev, heroSubtitle: e.target.value}))} />
                   </div>
                 </div>
              </div>
            </div>

            {/* Seção de Risco (Status) */}
            <div className="pt-4">
              <div className={`p-5 rounded-xl border ${formData.active ? 'border-slate-200 bg-slate-50' : 'border-red-200 bg-red-50'} transition-colors`}>
                <div className="flex items-start sm:items-center justify-between gap-4 flex-col sm:flex-row">
                  <div>
                    <h3 className={`text-base font-semibold flex items-center gap-2 ${formData.active ? 'text-slate-900' : 'text-red-700'}`}>
                      {!formData.active && <AlertTriangle size={18} />}
                      Status da Empresa
                    </h3>
                    <p className={`text-sm mt-1 ${formData.active ? 'text-slate-500' : 'text-red-600/80'}`}>
                      {formData.active 
                        ? 'Sua empresa está ativa. Todos os usuários e administradores têm acesso normal.' 
                        : 'Empresa inativada. Os usuários não poderão fazer login até que seja reativada.'}
                    </p>
                  </div>
                  <div className="flex items-center gap-3 bg-white px-4 py-2 rounded-lg border border-slate-200 shadow-sm shrink-0">
                    <Label className="font-medium text-slate-700 cursor-pointer">
                      {formData.active ? 'Ativa' : 'Inativa'}
                    </Label>
                    <Switch 
                      checked={formData.active} 
                      onCheckedChange={(checked) => setFormData(prev => ({...prev, active: checked}))} 
                    />
                  </div>
                </div>
              </div>
            </div>

          </div>

          <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-end">
            <Button type="submit" className="bg-indigo-600 hover:bg-indigo-700 text-white flex items-center gap-2 px-6">
              <Save size={18} /> Salvar Configurações
            </Button>
          </div>
        </div>
      </form>
    </div>
  );
};

import { useState, useMemo } from 'react';
import { useParams } from 'react-router-dom';
import { useAppStore } from '../../store/useAppStore';
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'sonner';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { CheckCircle2, XCircle, Edit2, Trash2, Shield, User as UserIcon, Users, Activity, Eye, BookOpen, Calendar, Store, Upload, FileSpreadsheet, AlertCircle, Download } from 'lucide-react';
import { User } from '../../types';
import * as XLSX from 'xlsx';

const isValidCPF = (cpf: string) => {
  cpf = cpf.replace(/[^\d]+/g, '');
  if (cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;
  let sum = 0, rest;
  for (let i = 1; i <= 9; i++) sum = sum + parseInt(cpf.substring(i-1, i)) * (11 - i);
  rest = (sum * 10) % 11;
  if ((rest === 10) || (rest === 11)) rest = 0;
  if (rest !== parseInt(cpf.substring(9, 10))) return false;
  sum = 0;
  for (let i = 1; i <= 10; i++) sum = sum + parseInt(cpf.substring(i-1, i)) * (12 - i);
  rest = (sum * 10) % 11;
  if ((rest === 10) || (rest === 11)) rest = 0;
  if (rest !== parseInt(cpf.substring(10, 11))) return false;
  return true;
};

export const AdminUsers = () => {
  const { linkName } = useParams();
  const { user: currentUser } = useAuth();
  const { companies, users, addUser, updateUser, deleteUser, toggleUserStatus, contentViews, contents, simpleLinks, repositories, orgUnits } = useAppStore();

  const company = companies.find(c => c.linkName === linkName);
  const companyUsers = users.filter(u => u.companyId === company?.id)
                            .sort((a, b) => new Date(b.createdAt || '').getTime() - new Date(a.createdAt || '').getTime());

  const companyUnits = orgUnits.filter(u => u.companyId === company?.id && u.active);
  const unitLabel = company?.orgUnitName || 'Unidade';

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '', email: '', cpf: '', password: '', role: 'USER' as 'ADMIN' | 'USER', active: true, orgUnitId: ''
  });

  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [userToDelete, setUserToDelete] = useState<{id: string, name: string} | null>(null);

  const [isActivityOpen, setIsActivityOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);

  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [importStep, setImportStep] = useState<'upload' | 'preview'>('upload');
  const [parsedData, setParsedData] = useState<any[]>([]);

  const userMetrics = useMemo(() => {
    if (!selectedUser) return null;
    const views = contentViews.filter(v => v.userId === selectedUser.id);
    let lastAccess = '';
    const contentMap = new Map<string, any>();

    views.forEach(v => {
      if (!lastAccess || new Date(v.viewedAt) > new Date(lastAccess)) lastAccess = v.viewedAt;
      const existing = contentMap.get(v.contentId);
      if (existing) {
        existing.viewCount += 1;
        if (new Date(v.viewedAt) > new Date(existing.lastView)) existing.lastView = v.viewedAt;
      } else {
        contentMap.set(v.contentId, { viewCount: 1, lastView: v.viewedAt, repoId: v.repositoryId, type: v.contentType });
      }
    });

    const history = Array.from(contentMap.entries()).map(([contentId, data]) => {
      let title = 'Conteúdo Excluído ou Desconhecido';
      const fullC = contents.find(c => c.id === contentId);
      if (fullC) title = fullC.title;
      else {
         const sLink = simpleLinks.find(l => l.id === contentId);
         if (sLink) title = sLink.name;
      }
      const repo = repositories.find(r => r.id === data.repoId);
      return { id: contentId, title, type: data.type, repoName: repo ? repo.name : 'Repositório Excluído', viewCount: data.viewCount, lastView: data.lastView };
    }).sort((a, b) => new Date(b.lastView).getTime() - new Date(a.lastView).getTime());

    return { totalViews: views.length, uniqueContents: contentMap.size, lastAccess, history };
  }, [selectedUser, contentViews, contents, simpleLinks, repositories]);

  if (!company) return null;

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setTimeout(() => setEditingId(null), 300);
  };

  const handleCloseDelete = () => {
    setIsDeleteOpen(false);
    setTimeout(() => setUserToDelete(null), 300);
  };

  const handleCloseActivity = () => {
    setIsActivityOpen(false);
    setTimeout(() => setSelectedUser(null), 300);
  };

  const handleCloseImport = () => {
    setIsImportModalOpen(false);
    setTimeout(() => {
      setImportStep('upload');
      setParsedData([]);
    }, 300);
  };

  const openCreate = () => {
    setEditingId(null);
    setFormData({ name: '', email: '', cpf: '', password: '', role: 'USER', active: true, orgUnitId: '' });
    setIsFormOpen(true);
  };

  const openEdit = (user: User) => {
    setEditingId(user.id);
    setFormData({ name: user.name, email: user.email || '', cpf: user.cpf || '', password: '', role: user.role as 'ADMIN' | 'USER', active: user.active !== false, orgUnitId: user.orgUnitId || '' });
    setIsFormOpen(true);
  };

  const openActivity = (user: User) => { setSelectedUser(user); setIsActivityOpen(true); };

  const handleSaveUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return toast.error('Nome é obrigatório.');
    if (!editingId && !formData.password) return toast.error('A senha é obrigatória para novos usuários.');

    if (formData.email) {
       const emailExists = users.some(u => u.email && u.email === formData.email && u.id !== editingId);
       if (emailExists) return toast.error('Este e-mail já está em uso por outro usuário.');
    }

    let cleanCpf = formData.cpf.replace(/\D/g, '');
    if (cleanCpf) {
       if (!isValidCPF(cleanCpf)) return toast.error('CPF inválido.');
       const cpfExists = users.some(u => u.cpf === cleanCpf && u.id !== editingId);
       if (cpfExists) return toast.error('Este CPF já está cadastrado no sistema.');
    }

    const payload = {
      name: formData.name,
      email: formData.email || undefined,
      cpf: cleanCpf || undefined,
      role: formData.role,
      active: formData.active,
      orgUnitId: formData.orgUnitId || undefined,
      status: 'ACTIVE' as const
    };

    if (editingId) {
      updateUser(editingId, { ...payload, ...(formData.password ? { password: formData.password } : {}) });
      toast.success('Usuário atualizado com sucesso!');
    } else {
      addUser({ companyId: company.id, password: formData.password, ...payload });
      toast.success('Usuário criado com sucesso!');
    }

    handleCloseForm();
  };

  const handleDeleteUser = () => {
    if (userToDelete) {
      if (userToDelete.id === currentUser?.id) {
         toast.error('Você não pode excluir a sua própria conta.');
      } else {
         deleteUser(userToDelete.id);
         toast.success('Usuário excluído.');
      }
    }
    handleCloseDelete();
  };

  const toggleStatus = (user: User) => {
    if (user.id === currentUser?.id) return toast.error('Você não pode inativar a sua própria conta.');
    toggleUserStatus(user.id);
    toast.success(`Status alterado para ${user.active === false ? 'Ativo' : 'Inativo'}.`);
  };

  const handleDownloadTemplate = () => {
    const ws = XLSX.utils.json_to_sheet([
      { Nome: 'João da Silva', CPF: '12345678901' },
      { Nome: 'Maria Oliveira', CPF: '09876543210' }
    ]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Modelo Importação');
    XLSX.writeFile(wb, 'modelo_usuarios_entstore.xlsx');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = new Uint8Array(evt.target?.result as ArrayBuffer);
        const wb = XLSX.read(data, { type: 'array' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rows = XLSX.utils.sheet_to_json(ws, { defval: '' }); // defval garante que colunas vazias não quebrem as keys

        const cpfSet = new Set<string>();
        // Pega os usuários no exato momento para evitar stale state caso usuários tenham acabado de ser criados
        const allUsers = useAppStore.getState().users;

        const processed = rows.map((row: any, index: number) => {
          const keys = Object.keys(row);
          const nomeKey = keys.find(k => k.toLowerCase().includes('nome'));
          const cpfKey = keys.find(k => k.toLowerCase().includes('cpf'));

          const nome = nomeKey ? String(row[nomeKey]).trim() : '';
          let cpfRaw = cpfKey ? row[cpfKey] : '';

          // Previne formato numérico tirando zeros a esquerda do excel
          if (typeof cpfRaw === 'number') cpfRaw = cpfRaw.toString().padStart(11, '0');
          const cpf = String(cpfRaw).replace(/\D/g, '');

          const errors = [];
          let isDuplicate = false;

          if (!nome) errors.push('Nome vazio');
          if (!cpf) {
             errors.push('CPF vazio');
          } else {
             // 1. Checa se já existe no banco (Mais importante!)
             if (allUsers.some(u => u.cpf === cpf)) {
               errors.push('CPF já cadastrado no sistema');
               isDuplicate = true;
             } 
             // 2. Checa se tá duplicado dentro do próprio arquivo excel
             else if (cpfSet.has(cpf)) {
               errors.push('CPF duplicado nesta planilha');
               isDuplicate = true;
             } 
             // 3. Valida matemática do CPF apenas se for novo
             else if (!isValidCPF(cpf)) {
               errors.push('CPF inválido');
             } 
             // Se passou, adiciona no set de validação atual
             else {
               cpfSet.add(cpf);
             }
          }

          return { nome, cpf, valid: errors.length === 0, errors, isDuplicate, rowNum: index + 2 };
        });

        setParsedData(processed);
        setImportStep('preview');
      } catch (err) {
        toast.error('Erro ao ler a planilha. Verifique o formato do arquivo.');
      }
    };
    reader.readAsArrayBuffer(file);
    e.target.value = ''; 
  };

  const handleConfirmImport = () => {
    const validRows = parsedData.filter(r => r.valid);
    if (validRows.length === 0) return toast.error('Nenhuma linha válida para importar.');

    validRows.forEach(row => {
      addUser({
        companyId: company.id,
        name: row.nome,
        cpf: row.cpf,
        password: '123456',
        role: 'USER',
        status: 'PENDING_SETUP',
        firstAccess: true,
        active: true,
      });
    });

    toast.success(`${validRows.length} usuários importados com sucesso!`);
    handleCloseImport();
  };

  const totalRows = parsedData.length;
  const validRows = parsedData.filter(r => r.valid);
  const duplicateRows = parsedData.filter(r => !r.valid && r.isDuplicate);
  const errorRows = parsedData.filter(r => !r.valid && !r.isDuplicate);

  return (
    <div className="max-w-6xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
         <div>
           <h1 className="text-2xl font-bold text-slate-900">Usuários</h1>
           <p className="text-sm text-slate-500 mt-1">Gerencie quem tem acesso aos conteúdos da {company.name}.</p>
         </div>
         <div className="flex gap-2 w-full sm:w-auto">
            <Button variant="outline" onClick={() => { setIsImportModalOpen(true); setImportStep('upload'); }} className="bg-white border-slate-200 flex-1 sm:flex-none text-indigo-600 hover:text-indigo-700 hover:bg-indigo-50 border-indigo-200">
               <Upload size={16} className="mr-2" /> Importar Planilha
            </Button>
